import React from 'react';

const WhoCanUse = () => {
  return (
    <section className="section light fade-element">
      <h2>Who Can Use It?</h2>
      <div className="card-row">
        <div className="card">Residents</div>
        <div className="card">Barangay Officials</div>
      </div>
    </section>
  );
};

export default WhoCanUse;
